public void  init()
{

    next init();
    ETG_ProductReceiptQualityGrp productReceiptQualityGrp;

    ttsbegin;
    update_recordset productReceiptQualityGrp
        setting ResultValue = 0
            where productReceiptQualityGrp.PurchId ==  purchFormLetter.purchTable().PurchId;
    ttscommit;

}

void closeOk()
{      
    FormRun                     form = this as FormRun;
    FormDataSource              PurchParmTable_ds = form.dataSource(formDataSourceStr(PurchEditLines, PurchParmTable)) as FormDataSource;
    PurchParmTable              PurchParmTable    = PurchParmTable_ds.cursor();
    PurchParmLine               PurchParmLineLoop,PurchParmLine;
    CustPackingSlipTrans        custPackingSlipTrans;
    VendPackingSlipTrans        vendPackingSlipTrans;
    Qty                         qtysales = 0, qtypurch = 0,qtyRemain;
    Description                 PurchParmLineLoopid;

    if(curExt() != "O001" || curExt() != "P031")
    {
        if(PurchParmTable.purchTable().InterCompanySalesId)
        {
            while select RecId,InventTransId,ReceiveNow,ItemId from PurchParmLineLoop
            where PurchParmLineLoop.ParmId == PurchParmTable.ParmId
            {
                qtyRemain = PurchLine::findInventTransId(PurchParmLineLoop.InventTransId).RemainPurchPhysical - PurchParmLineLoop.ReceiveNow;


                select firstonly crosscompany RecId from custPackingSlipTrans
                where custPackingSlipTrans.InterCompanyInventTransId == PurchParmLineLoop.InventTransId
                    && custPackingSlipTrans.Qty == PurchParmLineLoop.ReceiveNow
                    && custPackingSlipTrans.Remain ==  qtyRemain;

                if(!custPackingSlipTrans)
                {
                    PurchParmLineLoopid = strFmt('%1', PurchParmLineLoop.ItemId);
                    throw error("@ETG:PackingSlipProductReceiptValidationMsg"+ ' ' + PurchParmLineLoopid);
                }

            }
        }
    }

    next closeOk();
}
